import React from 'react';
import { motion, useMotionValue, useTransform, animate } from 'framer-motion';

const StatCounter = ({ from, to, suffix, title }) => {
  const count = useMotionValue(from);
  const rounded = useTransform(count, (latest) => Math.round(latest));

  React.useEffect(() => {
    const controls = animate(count, to, { duration: 2, ease: "easeOut" });
    return controls.stop;
  }, [count, to]);

  return (
    <div className="text-center p-8 bg-white/[0.02] border border-white/5 rounded-3xl backdrop-blur-sm">
      <motion.div className="text-5xl md:text-7xl font-black text-cyan-400 mb-2">
        {rounded}{suffix}
      </motion.div>
      <div className="text-gray-400 font-semibold tracking-wider uppercase text-sm">{title}</div>
    </div>
  );
};

